from __future__ import annotations

import base64
import json
import time
from typing import Any

import replicate

from .config import ExtractorConfig
from .exceptions import AnalysisError
from .schemas import ExtractionMode


class ReplicateVisionAnalyzer:
    def __init__(self, config: ExtractorConfig):
        self.config = config
        if config.replicate_api_token:
            self.client = replicate.Client(api_token=config.replicate_api_token)
        else:
            self.client = replicate.Client()

    def analyze_page(
        self,
        *,
        image_bytes: bytes,
        mode: ExtractionMode,
        structured_schema: dict[str, Any] | None = None,
    ) -> str | dict[str, Any]:
        prompt = self._build_prompt(mode=mode, structured_schema=structured_schema)
        raw = self._run_with_retries(prompt=prompt, image_bytes=image_bytes)

        if mode == ExtractionMode.STRUCTURED:
            return self._extract_json_object(raw)
        return raw.strip()

    def repair_structured_output(
        self,
        *,
        candidate: dict[str, Any],
        validation_error: str,
        structured_schema: dict[str, Any] | None,
    ) -> dict[str, Any]:
        schema_text = json.dumps(structured_schema, indent=2) if structured_schema else "{}"
        prompt = (
            "You must return only valid JSON that matches the schema. "
            "Do not include markdown or extra text.\n\n"
            f"Schema:\n{schema_text}\n\n"
            f"Validation error:\n{validation_error}\n\n"
            f"Candidate JSON:\n{json.dumps(candidate, indent=2)}"
        )
        repaired = self._run_with_retries(prompt=prompt, image_bytes=None)
        return self._extract_json_object(repaired)

    def _build_prompt(
        self,
        *,
        mode: ExtractionMode,
        structured_schema: dict[str, Any] | None,
    ) -> str:
        if mode == ExtractionMode.FULL_TEXT:
            return (
                "Transcribe all text visible on this page. Preserve layout hints with line breaks. "
                "Do not summarize."
            )

        if mode == ExtractionMode.SUMMARY:
            return (
                "Summarize this page in 3-5 concise sentences. Include critical numbers, dates, "
                "entities, and actions."
            )

        schema_text = ""
        if structured_schema is not None:
            schema_text = f"\nJSON schema to follow:\n{json.dumps(structured_schema, indent=2)}"

        return (
            "Extract structured information from this page and return JSON only. "
            "No markdown, no explanation, no code fences. "
            "Use null for unknown values."
            f"{schema_text}"
        )

    def _run_with_retries(self, *, prompt: str, image_bytes: bytes | None) -> str:
        candidate_models: list[str] = [self.config.model]
        if self.config.fallback_model and self.config.fallback_model != self.config.model:
            candidate_models.append(self.config.fallback_model)

        last_error: Exception | None = None

        for model in candidate_models:
            for attempt in range(1, self.config.max_retries + 1):
                try:
                    input_payload = self._build_input_payload(prompt=prompt, image_bytes=image_bytes)
                    try:
                        output = self.client.run(
                            model,
                            input=input_payload,
                            wait=self.config.timeout_seconds,
                        )
                    except TypeError:
                        output = self.client.run(model, input=input_payload)
                    return self._normalize_output(output)
                except Exception as exc:
                    last_error = exc
                    if attempt >= self.config.max_retries:
                        break
                    sleep_seconds = self.config.retry_backoff_seconds * (2 ** (attempt - 1))
                    time.sleep(sleep_seconds)

        raise AnalysisError(f"Replicate analysis failed: {last_error}")

    def _build_input_payload(self, *, prompt: str, image_bytes: bytes | None) -> dict[str, Any]:
        payload: dict[str, Any] = {
            "prompt": prompt,
            "max_completion_tokens": 4096,
            "temperature": 0.0,
            "top_p": 1.0,
            "presence_penalty": 0,
            "frequency_penalty": 0,
        }

        if image_bytes is not None:
            payload["image_input"] = [self._bytes_to_data_url(image_bytes)]

        return payload

    @staticmethod
    def _bytes_to_data_url(image_bytes: bytes, mime_type: str = "image/png") -> str:
        encoded = base64.b64encode(image_bytes).decode("ascii")
        return f"data:{mime_type};base64,{encoded}"

    @staticmethod
    def _normalize_output(output: Any) -> str:
        if isinstance(output, str):
            return output
        if isinstance(output, list):
            return "".join(str(part) for part in output)
        if hasattr(output, "__iter__"):
            return "".join(str(part) for part in output)
        return str(output)

    def _extract_json_object(self, text: str) -> dict[str, Any]:
        stripped = text.strip()
        try:
            return json.loads(stripped)
        except json.JSONDecodeError:
            pass

        if "```" in stripped:
            fenced = stripped.split("```")
            for block in fenced:
                candidate = block.strip()
                if candidate.startswith("json"):
                    candidate = candidate[4:].strip()
                try:
                    return json.loads(candidate)
                except json.JSONDecodeError:
                    continue

        start = stripped.find("{")
        end = stripped.rfind("}")
        if start != -1 and end != -1 and end > start:
            candidate = stripped[start : end + 1]
            try:
                return json.loads(candidate)
            except json.JSONDecodeError:
                pass

        raise AnalysisError("Model did not return valid JSON for structured extraction")

from __future__ import annotations

from concurrent.futures import ThreadPoolExecutor, as_completed
from datetime import UTC, datetime
from pathlib import Path
from typing import Any

from pydantic import BaseModel, ValidationError

from .analyzer import ReplicateVisionAnalyzer
from .cache import CacheManager, CacheMetadata, compute_content_hash
from .config import CacheMode, ExtractorConfig
from .converter import PDFConverter
from .exceptions import SchemaValidationError
from .schemas import BatchExtractionItem, BatchItemStatus, ExtractionMode, ExtractionResult


class PDFExtractor:
    def __init__(self, config: ExtractorConfig | None = None):
        self.config = config or ExtractorConfig()
        self.config.validate()

        self.converter = PDFConverter()
        self.cache = CacheManager(
            base_cache_dir=self.config.cache_dir,
            mode=self.config.cache_mode,
            ttl_days=self.config.cache_ttl_days,
        )
        self.analyzer = ReplicateVisionAnalyzer(self.config)

    def cleanup_persistent_cache(self) -> int:
        return self.cache.cleanup_expired()

    def extract_many(
        self,
        pdf_paths: list[str | Path],
        *,
        mode: ExtractionMode,
        schema: type[BaseModel] | None = None,
        max_workers: int = 4,
        continue_on_error: bool = True,
    ) -> list[BatchExtractionItem]:
        if max_workers < 1:
            raise ValueError("max_workers must be >= 1")
        if not pdf_paths:
            return []

        normalized_paths = [Path(p).expanduser().resolve() for p in pdf_paths]
        results: list[BatchExtractionItem | None] = [None] * len(normalized_paths)

        with ThreadPoolExecutor(max_workers=max_workers) as executor:
            futures = {
                executor.submit(self._run_single_batch_item, path, mode, schema): idx
                for idx, path in enumerate(normalized_paths)
            }

            for future in as_completed(futures):
                idx = futures[future]
                path = normalized_paths[idx]
                try:
                    result = future.result()
                    results[idx] = BatchExtractionItem(
                        pdf_path=str(path),
                        status=BatchItemStatus.SUCCESS,
                        result=result,
                    )
                except Exception as exc:
                    if not continue_on_error:
                        raise
                    results[idx] = BatchExtractionItem(
                        pdf_path=str(path),
                        status=BatchItemStatus.ERROR,
                        error=str(exc),
                    )

        return [item for item in results if item is not None]

    def _run_single_batch_item(
        self,
        path: Path,
        mode: ExtractionMode,
        schema: type[BaseModel] | None,
    ) -> ExtractionResult:
        worker = PDFExtractor(self.config)
        return worker.extract(path, mode=mode, schema=schema)

    def extract(
        self,
        pdf_path: str | Path,
        *,
        mode: ExtractionMode,
        schema: type[BaseModel] | None = None,
    ) -> ExtractionResult:
        path = Path(pdf_path).expanduser().resolve()
        if not path.exists():
            raise FileNotFoundError(f"PDF not found: {path}")

        if mode == ExtractionMode.STRUCTURED and schema is None:
            raise ValueError("Structured mode requires a Pydantic schema class")

        source_hash = compute_content_hash(path)
        schema_json = schema.model_json_schema() if schema is not None else None

        work_dir = self.cache.resolve_work_dir(source_hash)

        try:
            pages = self._prepare_pages(path=path, source_hash=source_hash, work_dir=work_dir)

            page_outputs: list[str | dict[str, Any]] = []
            for page in pages:
                page_outputs.append(
                    self.analyzer.analyze_page(
                        image_bytes=page.image_bytes,
                        mode=mode,
                        structured_schema=schema_json,
                    )
                )

            content = self._aggregate_outputs(
                outputs=page_outputs,
                mode=mode,
                schema=schema,
                schema_json=schema_json,
            )

            result = ExtractionResult(
                extraction_mode=mode,
                content=content,
                metadata={
                    "source_hash": source_hash,
                    "page_count": len(pages),
                    "model": self.config.model,
                    "cache_mode": self.config.cache_mode.value,
                    "generated_at": datetime.now(UTC).isoformat(),
                },
            )
            return result
        finally:
            self.cache.cleanup()

    def _prepare_pages(self, *, path: Path, source_hash: str, work_dir: Path | None):
        if self.config.cache_mode == CacheMode.PERSISTENT and work_dir is not None:
            if not self.config.force_conversion and self.cache.is_cache_hit(
                work_dir,
                source_hash=source_hash,
                dpi=self.config.dpi,
                max_pages=self.config.max_pages,
            ):
                return self.converter.load_from_dir(work_dir)

            pages = self.converter.convert(
                path,
                dpi=self.config.dpi,
                output_dir=work_dir,
                max_pages=self.config.max_pages,
            )
            self.cache.write_metadata(
                work_dir,
                CacheMetadata(
                    page_count=len(pages),
                    dpi=self.config.dpi,
                    created_at=datetime.now(UTC).isoformat(),
                    source_hash=source_hash,
                    max_pages=self.config.max_pages,
                ),
            )
            return pages

        return self.converter.convert(
            path,
            dpi=self.config.dpi,
            output_dir=work_dir,
            max_pages=self.config.max_pages,
        )

    def _aggregate_outputs(
        self,
        *,
        outputs: list[str | dict[str, Any]],
        mode: ExtractionMode,
        schema: type[BaseModel] | None,
        schema_json: dict[str, Any] | None,
    ) -> str | dict[str, Any]:
        if mode == ExtractionMode.FULL_TEXT:
            chunks = [f"[Page {idx}]\n{value}" for idx, value in enumerate(outputs, start=1)]
            return "\n\n".join(chunks)

        if mode == ExtractionMode.SUMMARY:
            chunks = [f"Page {idx}: {value}" for idx, value in enumerate(outputs, start=1)]
            return "\n".join(chunks)

        structured_outputs = [value for value in outputs if isinstance(value, dict)]
        merged = self._merge_dicts(structured_outputs)

        if schema is None:
            return merged

        try:
            validated = schema.model_validate(merged)
            return validated.model_dump()
        except ValidationError as exc:
            repaired = self.analyzer.repair_structured_output(
                candidate=merged,
                validation_error=str(exc),
                structured_schema=schema_json,
            )
            try:
                validated = schema.model_validate(repaired)
                return validated.model_dump()
            except ValidationError as second_exc:
                raise SchemaValidationError(
                    "Structured output failed schema validation after repair"
                ) from second_exc

    def _merge_dicts(self, items: list[dict[str, Any]]) -> dict[str, Any]:
        merged: dict[str, Any] = {}
        for item in items:
            merged = self._merge_two(merged, item)
        return merged

    def _merge_two(self, left: dict[str, Any], right: dict[str, Any]) -> dict[str, Any]:
        merged = dict(left)
        for key, value in right.items():
            if key not in merged:
                merged[key] = value
                continue

            left_value = merged[key]
            if isinstance(left_value, dict) and isinstance(value, dict):
                merged[key] = self._merge_two(left_value, value)
            elif isinstance(left_value, list) and isinstance(value, list):
                merged[key] = left_value + [v for v in value if v not in left_value]
            elif left_value in (None, "", [], {}):
                merged[key] = value
        return merged

from __future__ import annotations

import hashlib
import json
import tempfile
from dataclasses import dataclass
from datetime import UTC, datetime, timedelta
from pathlib import Path
from shutil import rmtree
from typing import Any

from .config import CacheMode
from .exceptions import CacheError


def compute_content_hash(file_path: Path) -> str:
    sha256 = hashlib.sha256()
    with file_path.open("rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            sha256.update(chunk)
    return sha256.hexdigest()


@dataclass(slots=True)
class CacheMetadata:
    page_count: int
    dpi: int
    created_at: str
    source_hash: str
    max_pages: int | None = None
    converter_version: str = "1"

    def as_dict(self) -> dict[str, Any]:
        return {
            "page_count": self.page_count,
            "dpi": self.dpi,
            "created_at": self.created_at,
            "source_hash": self.source_hash,
            "max_pages": self.max_pages,
            "converter_version": self.converter_version,
        }


class CacheManager:
    def __init__(self, base_cache_dir: Path, mode: CacheMode, ttl_days: int = 7):
        self.base_cache_dir = base_cache_dir
        self.mode = mode
        self.ttl_days = ttl_days
        self._ephemeral_dirs: list[Path] = []

    @staticmethod
    def cache_key_dir(source_hash: str, base_cache_dir: Path) -> Path:
        return base_cache_dir / source_hash[:16]

    def resolve_work_dir(self, source_hash: str) -> Path | None:
        if self.mode == CacheMode.DISABLED:
            return None

        if self.mode == CacheMode.PERSISTENT:
            work_dir = self.cache_key_dir(source_hash, self.base_cache_dir)
            work_dir.mkdir(parents=True, exist_ok=True)
            return work_dir

        temp_dir = Path(tempfile.mkdtemp(prefix=f"pdfx-{source_hash[:8]}-"))
        self._ephemeral_dirs.append(temp_dir)
        return temp_dir

    def cleanup(self) -> None:
        for path in self._ephemeral_dirs:
            if path.exists():
                rmtree(path, ignore_errors=True)
        self._ephemeral_dirs.clear()

    def metadata_path(self, cache_dir: Path) -> Path:
        return cache_dir / "metadata.json"

    def read_metadata(self, cache_dir: Path) -> CacheMetadata | None:
        path = self.metadata_path(cache_dir)
        if not path.exists():
            return None
        try:
            data = json.loads(path.read_text(encoding="utf-8"))
            return CacheMetadata(
                page_count=int(data["page_count"]),
                dpi=int(data["dpi"]),
                created_at=str(data["created_at"]),
                source_hash=str(data["source_hash"]),
                max_pages=data.get("max_pages"),
                converter_version=str(data.get("converter_version", "1")),
            )
        except (KeyError, ValueError, TypeError, json.JSONDecodeError) as exc:
            raise CacheError(f"Invalid cache metadata: {path}") from exc

    def write_metadata(self, cache_dir: Path, metadata: CacheMetadata) -> None:
        path = self.metadata_path(cache_dir)
        path.write_text(json.dumps(metadata.as_dict(), indent=2), encoding="utf-8")

    def list_page_images(self, cache_dir: Path) -> list[Path]:
        return sorted(cache_dir.glob("page_*.png"))

    def is_cache_hit(
        self,
        cache_dir: Path,
        *,
        source_hash: str,
        dpi: int,
        max_pages: int | None,
    ) -> bool:
        if not cache_dir.exists():
            return False

        try:
            metadata = self.read_metadata(cache_dir)
        except CacheError:
            return False
        if metadata is None:
            return False

        if metadata.source_hash != source_hash or metadata.dpi != dpi:
            return False

        if metadata.max_pages != max_pages:
            return False

        pages = self.list_page_images(cache_dir)
        return len(pages) == metadata.page_count and metadata.page_count > 0

    def cleanup_expired(self) -> int:
        if self.mode != CacheMode.PERSISTENT:
            return 0
        if not self.base_cache_dir.exists():
            return 0

        now = datetime.now(UTC)
        cutoff = now - timedelta(days=self.ttl_days)
        removed = 0

        for entry in self.base_cache_dir.iterdir():
            if not entry.is_dir():
                continue
            metadata_path = entry / "metadata.json"
            if not metadata_path.exists():
                continue
            try:
                metadata = self.read_metadata(entry)
                if metadata is None:
                    continue
                created_at = datetime.fromisoformat(metadata.created_at)
                if created_at.tzinfo is None:
                    created_at = created_at.replace(tzinfo=UTC)
                if created_at < cutoff:
                    rmtree(entry, ignore_errors=True)
                    removed += 1
            except Exception:
                continue

        return removed

class PDFExtractorError(Exception):
    """Base exception for the package."""


class CacheError(PDFExtractorError):
    """Raised when cache operations fail."""


class ConversionError(PDFExtractorError):
    """Raised when PDF conversion fails."""


class AnalysisError(PDFExtractorError):
    """Raised when model analysis fails."""


class SchemaValidationError(PDFExtractorError):
    """Raised when structured output cannot be validated."""

from __future__ import annotations

import base64
import json
import time
from typing import Any

import replicate

from .config import ExtractorConfig
from .exceptions import AnalysisError
from .schemas import ExtractionMode


class ReplicateVisionAnalyzer:
    def __init__(self, config: ExtractorConfig):
        self.config = config
        if config.replicate_api_token:
            self.client = replicate.Client(api_token=config.replicate_api_token)
        else:
            self.client = replicate.Client()

    def analyze_page(
        self,
        *,
        image_bytes: bytes,
        mode: ExtractionMode,
        structured_schema: dict[str, Any] | None = None,
    ) -> str | dict[str, Any]:
        prompt = self._build_prompt(mode=mode, structured_schema=structured_schema)
        raw = self._run_with_retries(prompt=prompt, image_bytes=image_bytes)

        if mode == ExtractionMode.STRUCTURED:
            return self._extract_json_object(raw)
        return raw.strip()

    def repair_structured_output(
        self,
        *,
        candidate: dict[str, Any],
        validation_error: str,
        structured_schema: dict[str, Any] | None,
    ) -> dict[str, Any]:
        schema_text = json.dumps(structured_schema, indent=2) if structured_schema else "{}"
        prompt = (
            "You must return only valid JSON that matches the schema. "
            "Do not include markdown or extra text.\n\n"
            f"Schema:\n{schema_text}\n\n"
            f"Validation error:\n{validation_error}\n\n"
            f"Candidate JSON:\n{json.dumps(candidate, indent=2)}"
        )
        repaired = self._run_with_retries(prompt=prompt, image_bytes=None)
        return self._extract_json_object(repaired)

    def _build_prompt(
        self,
        *,
        mode: ExtractionMode,
        structured_schema: dict[str, Any] | None,
    ) -> str:
        if mode == ExtractionMode.FULL_TEXT:
            return (
                "Transcribe all text visible on this page. Preserve layout hints with line breaks. "
                "Do not summarize."
            )

        if mode == ExtractionMode.SUMMARY:
            return (
                "Summarize this page in 3-5 concise sentences. Include critical numbers, dates, "
                "entities, and actions."
            )

        schema_text = ""
        if structured_schema is not None:
            schema_text = f"\nJSON schema to follow:\n{json.dumps(structured_schema, indent=2)}"

        return (
            "Extract structured information from this page and return JSON only. "
            "No markdown, no explanation, no code fences. "
            "Use null for unknown values."
            f"{schema_text}"
        )

    def _run_with_retries(self, *, prompt: str, image_bytes: bytes | None) -> str:
        candidate_models: list[str] = [self.config.model]
        if self.config.fallback_model and self.config.fallback_model != self.config.model:
            candidate_models.append(self.config.fallback_model)

        last_error: Exception | None = None

        for model in candidate_models:
            for attempt in range(1, self.config.max_retries + 1):
                try:
                    input_payload = self._build_input_payload(prompt=prompt, image_bytes=image_bytes)
                    try:
                        output = self.client.run(
                            model,
                            input=input_payload,
                            wait=self.config.timeout_seconds,
                        )
                    except TypeError:
                        output = self.client.run(model, input=input_payload)
                    return self._normalize_output(output)
                except Exception as exc:
                    last_error = exc
                    if attempt >= self.config.max_retries:
                        break
                    sleep_seconds = self.config.retry_backoff_seconds * (2 ** (attempt - 1))
                    time.sleep(sleep_seconds)

        raise AnalysisError(f"Replicate analysis failed: {last_error}")

    def _build_input_payload(self, *, prompt: str, image_bytes: bytes | None) -> dict[str, Any]:
        payload: dict[str, Any] = {
            "prompt": prompt,
            "max_completion_tokens": 4096,
            "temperature": 0.0,
            "top_p": 1.0,
            "presence_penalty": 0,
            "frequency_penalty": 0,
        }

        if image_bytes is not None:
            payload["image_input"] = [self._bytes_to_data_url(image_bytes)]

        return payload

    @staticmethod
    def _bytes_to_data_url(image_bytes: bytes, mime_type: str = "image/png") -> str:
        encoded = base64.b64encode(image_bytes).decode("ascii")
        return f"data:{mime_type};base64,{encoded}"

    @staticmethod
    def _normalize_output(output: Any) -> str:
        if isinstance(output, str):
            return output
        if isinstance(output, list):
            return "".join(str(part) for part in output)
        if hasattr(output, "__iter__"):
            return "".join(str(part) for part in output)
        return str(output)

    def _extract_json_object(self, text: str) -> dict[str, Any]:
        stripped = text.strip()
        try:
            return json.loads(stripped)
        except json.JSONDecodeError:
            pass

        if "```" in stripped:
            fenced = stripped.split("```")
            for block in fenced:
                candidate = block.strip()
                if candidate.startswith("json"):
                    candidate = candidate[4:].strip()
                try:
                    return json.loads(candidate)
                except json.JSONDecodeError:
                    continue

        start = stripped.find("{")
        end = stripped.rfind("}")
        if start != -1 and end != -1 and end > start:
            candidate = stripped[start : end + 1]
            try:
                return json.loads(candidate)
            except json.JSONDecodeError:
                pass

        raise AnalysisError("Model did not return valid JSON for structured extraction")

from __future__ import annotations

import hashlib
import json
import tempfile
from dataclasses import dataclass
from datetime import UTC, datetime, timedelta
from pathlib import Path
from shutil import rmtree
from typing import Any

from .config import CacheMode
from .exceptions import CacheError


def compute_content_hash(file_path: Path) -> str:
    sha256 = hashlib.sha256()
    with file_path.open("rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            sha256.update(chunk)
    return sha256.hexdigest()


@dataclass(slots=True)
class CacheMetadata:
    page_count: int
    dpi: int
    created_at: str
    source_hash: str
    max_pages: int | None = None
    converter_version: str = "1"

    def as_dict(self) -> dict[str, Any]:
        return {
            "page_count": self.page_count,
            "dpi": self.dpi,
            "created_at": self.created_at,
            "source_hash": self.source_hash,
            "max_pages": self.max_pages,
            "converter_version": self.converter_version,
        }


class CacheManager:
    def __init__(self, base_cache_dir: Path, mode: CacheMode, ttl_days: int = 7):
        self.base_cache_dir = base_cache_dir
        self.mode = mode
        self.ttl_days = ttl_days
        self._ephemeral_dirs: list[Path] = []

    @staticmethod
    def cache_key_dir(source_hash: str, base_cache_dir: Path) -> Path:
        return base_cache_dir / source_hash[:16]

    def resolve_work_dir(self, source_hash: str) -> Path | None:
        if self.mode == CacheMode.DISABLED:
            return None

        if self.mode == CacheMode.PERSISTENT:
            work_dir = self.cache_key_dir(source_hash, self.base_cache_dir)
            work_dir.mkdir(parents=True, exist_ok=True)
            return work_dir

        temp_dir = Path(tempfile.mkdtemp(prefix=f"pdfx-{source_hash[:8]}-"))
        self._ephemeral_dirs.append(temp_dir)
        return temp_dir

    def cleanup(self) -> None:
        for path in self._ephemeral_dirs:
            if path.exists():
                rmtree(path, ignore_errors=True)
        self._ephemeral_dirs.clear()

    def metadata_path(self, cache_dir: Path) -> Path:
        return cache_dir / "metadata.json"

    def read_metadata(self, cache_dir: Path) -> CacheMetadata | None:
        path = self.metadata_path(cache_dir)
        if not path.exists():
            return None
        try:
            data = json.loads(path.read_text(encoding="utf-8"))
            return CacheMetadata(
                page_count=int(data["page_count"]),
                dpi=int(data["dpi"]),
                created_at=str(data["created_at"]),
                source_hash=str(data["source_hash"]),
                max_pages=data.get("max_pages"),
                converter_version=str(data.get("converter_version", "1")),
            )
        except (KeyError, ValueError, TypeError, json.JSONDecodeError) as exc:
            raise CacheError(f"Invalid cache metadata: {path}") from exc

    def write_metadata(self, cache_dir: Path, metadata: CacheMetadata) -> None:
        path = self.metadata_path(cache_dir)
        path.write_text(json.dumps(metadata.as_dict(), indent=2), encoding="utf-8")

    def list_page_images(self, cache_dir: Path) -> list[Path]:
        return sorted(cache_dir.glob("page_*.png"))

    def is_cache_hit(
        self,
        cache_dir: Path,
        *,
        source_hash: str,
        dpi: int,
        max_pages: int | None,
    ) -> bool:
        if not cache_dir.exists():
            return False

        try:
            metadata = self.read_metadata(cache_dir)
        except CacheError:
            return False
        if metadata is None:
            return False

        if metadata.source_hash != source_hash or metadata.dpi != dpi:
            return False

        if metadata.max_pages != max_pages:
            return False

        pages = self.list_page_images(cache_dir)
        return len(pages) == metadata.page_count and metadata.page_count > 0

    def cleanup_expired(self) -> int:
        if self.mode != CacheMode.PERSISTENT:
            return 0
        if not self.base_cache_dir.exists():
            return 0

        now = datetime.now(UTC)
        cutoff = now - timedelta(days=self.ttl_days)
        removed = 0

        for entry in self.base_cache_dir.iterdir():
            if not entry.is_dir():
                continue
            metadata_path = entry / "metadata.json"
            if not metadata_path.exists():
                continue
            try:
                metadata = self.read_metadata(entry)
                if metadata is None:
                    continue
                created_at = datetime.fromisoformat(metadata.created_at)
                if created_at.tzinfo is None:
                    created_at = created_at.replace(tzinfo=UTC)
                if created_at < cutoff:
                    rmtree(entry, ignore_errors=True)
                    removed += 1
            except Exception:
                continue

        return removed

from __future__ import annotations

from concurrent.futures import ThreadPoolExecutor, as_completed
from datetime import UTC, datetime
from pathlib import Path
from typing import Any

from pydantic import BaseModel, ValidationError

from .analyzer import ReplicateVisionAnalyzer
from .cache import CacheManager, CacheMetadata, compute_content_hash
from .config import CacheMode, ExtractorConfig
from .converter import PDFConverter
from .exceptions import SchemaValidationError
from .schemas import BatchExtractionItem, BatchItemStatus, ExtractionMode, ExtractionResult


class PDFExtractor:
    def __init__(self, config: ExtractorConfig | None = None):
        self.config = config or ExtractorConfig()
        self.config.validate()

        self.converter = PDFConverter()
        self.cache = CacheManager(
            base_cache_dir=self.config.cache_dir,
            mode=self.config.cache_mode,
            ttl_days=self.config.cache_ttl_days,
        )
        self.analyzer = ReplicateVisionAnalyzer(self.config)

    def cleanup_persistent_cache(self) -> int:
        return self.cache.cleanup_expired()

    def extract_many(
        self,
        pdf_paths: list[str | Path],
        *,
        mode: ExtractionMode,
        schema: type[BaseModel] | None = None,
        max_workers: int = 4,
        continue_on_error: bool = True,
    ) -> list[BatchExtractionItem]:
        if max_workers < 1:
            raise ValueError("max_workers must be >= 1")
        if not pdf_paths:
            return []

        normalized_paths = [Path(p).expanduser().resolve() for p in pdf_paths]
        results: list[BatchExtractionItem | None] = [None] * len(normalized_paths)

        with ThreadPoolExecutor(max_workers=max_workers) as executor:
            futures = {
                executor.submit(self._run_single_batch_item, path, mode, schema): idx
                for idx, path in enumerate(normalized_paths)
            }

            for future in as_completed(futures):
                idx = futures[future]
                path = normalized_paths[idx]
                try:
                    result = future.result()
                    results[idx] = BatchExtractionItem(
                        pdf_path=str(path),
                        status=BatchItemStatus.SUCCESS,
                        result=result,
                    )
                except Exception as exc:
                    if not continue_on_error:
                        raise
                    results[idx] = BatchExtractionItem(
                        pdf_path=str(path),
                        status=BatchItemStatus.ERROR,
                        error=str(exc),
                    )

        return [item for item in results if item is not None]

    def _run_single_batch_item(
        self,
        path: Path,
        mode: ExtractionMode,
        schema: type[BaseModel] | None,
    ) -> ExtractionResult:
        worker = PDFExtractor(self.config)
        return worker.extract(path, mode=mode, schema=schema)

    def extract(
        self,
        pdf_path: str | Path,
        *,
        mode: ExtractionMode,
        schema: type[BaseModel] | None = None,
    ) -> ExtractionResult:
        path = Path(pdf_path).expanduser().resolve()
        if not path.exists():
            raise FileNotFoundError(f"PDF not found: {path}")

        if mode == ExtractionMode.STRUCTURED and schema is None:
            raise ValueError("Structured mode requires a Pydantic schema class")

        source_hash = compute_content_hash(path)
        schema_json = schema.model_json_schema() if schema is not None else None

        work_dir = self.cache.resolve_work_dir(source_hash)

        try:
            pages = self._prepare_pages(path=path, source_hash=source_hash, work_dir=work_dir)

            page_outputs: list[str | dict[str, Any]] = []
            for page in pages:
                page_outputs.append(
                    self.analyzer.analyze_page(
                        image_bytes=page.image_bytes,
                        mode=mode,
                        structured_schema=schema_json,
                    )
                )

            content = self._aggregate_outputs(
                outputs=page_outputs,
                mode=mode,
                schema=schema,
                schema_json=schema_json,
            )

            result = ExtractionResult(
                extraction_mode=mode,
                content=content,
                metadata={
                    "source_hash": source_hash,
                    "page_count": len(pages),
                    "model": self.config.model,
                    "cache_mode": self.config.cache_mode.value,
                    "generated_at": datetime.now(UTC).isoformat(),
                },
            )
            return result
        finally:
            self.cache.cleanup()

    def _prepare_pages(self, *, path: Path, source_hash: str, work_dir: Path | None):
        if self.config.cache_mode == CacheMode.PERSISTENT and work_dir is not None:
            if not self.config.force_conversion and self.cache.is_cache_hit(
                work_dir,
                source_hash=source_hash,
                dpi=self.config.dpi,
                max_pages=self.config.max_pages,
            ):
                return self.converter.load_from_dir(work_dir)

            pages = self.converter.convert(
                path,
                dpi=self.config.dpi,
                output_dir=work_dir,
                max_pages=self.config.max_pages,
            )
            self.cache.write_metadata(
                work_dir,
                CacheMetadata(
                    page_count=len(pages),
                    dpi=self.config.dpi,
                    created_at=datetime.now(UTC).isoformat(),
                    source_hash=source_hash,
                    max_pages=self.config.max_pages,
                ),
            )
            return pages

        return self.converter.convert(
            path,
            dpi=self.config.dpi,
            output_dir=work_dir,
            max_pages=self.config.max_pages,
        )

    def _aggregate_outputs(
        self,
        *,
        outputs: list[str | dict[str, Any]],
        mode: ExtractionMode,
        schema: type[BaseModel] | None,
        schema_json: dict[str, Any] | None,
    ) -> str | dict[str, Any]:
        if mode == ExtractionMode.FULL_TEXT:
            chunks = [f"[Page {idx}]\n{value}" for idx, value in enumerate(outputs, start=1)]
            return "\n\n".join(chunks)

        if mode == ExtractionMode.SUMMARY:
            chunks = [f"Page {idx}: {value}" for idx, value in enumerate(outputs, start=1)]
            return "\n".join(chunks)

        structured_outputs = [value for value in outputs if isinstance(value, dict)]
        merged = self._merge_dicts(structured_outputs)

        if schema is None:
            return merged

        try:
            validated = schema.model_validate(merged)
            return validated.model_dump()
        except ValidationError as exc:
            repaired = self.analyzer.repair_structured_output(
                candidate=merged,
                validation_error=str(exc),
                structured_schema=schema_json,
            )
            try:
                validated = schema.model_validate(repaired)
                return validated.model_dump()
            except ValidationError as second_exc:
                raise SchemaValidationError(
                    "Structured output failed schema validation after repair"
                ) from second_exc

    def _merge_dicts(self, items: list[dict[str, Any]]) -> dict[str, Any]:
        merged: dict[str, Any] = {}
        for item in items:
            merged = self._merge_two(merged, item)
        return merged

    def _merge_two(self, left: dict[str, Any], right: dict[str, Any]) -> dict[str, Any]:
        merged = dict(left)
        for key, value in right.items():
            if key not in merged:
                merged[key] = value
                continue

            left_value = merged[key]
            if isinstance(left_value, dict) and isinstance(value, dict):
                merged[key] = self._merge_two(left_value, value)
            elif isinstance(left_value, list) and isinstance(value, list):
                merged[key] = left_value + [v for v in value if v not in left_value]
            elif left_value in (None, "", [], {}):
                merged[key] = value
        return merged

